    , REG_USER_ID
    , DEL_FLAG
    , SIGN_STATUS
) VALUES (
      #{ses.gateCd}
    , #{APP_DOC_NUM}
    , #{APP_DOC_CNT}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , 'P' -- 최초 상신은 P (결재중)
