mapper.update:
UPDATE STOCATCN
   SET SIGN_STATUS = #{SIGN_STATUS}
     , SIGN_DATE = 
                       SYSDATE
                       NULL

     , MOD_DATE = SYSDATE
     , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD = #{ses.gateCd}
   AND APP_DOC_NUM = #{APP_DOC_NUM}
   AND APP_DOC_CNT = #{APP_DOC_CNT}
   AND DEL_FLAG = '0'

UPDATE STOCATCH
   SET APP_DOC_NUM = #{APP_DOC_NUM}
     , APP_DOC_CNT = #{APP_DOC_CNT}
     , MOD_DATE = SYSDATE
     , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD = #{ses.gateCd}
   AND UUID = #{UUID}
   AND UUID_SQ = #{UUID_SQ}

UPDATE STOCATCH
   SET APP_DOC_NUM = NULL
     , APP_DOC_CNT = NULL
     , MOD_DATE = SYSDATE
     , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD = #{ses.gateCd}
   AND APP_DOC_NUM = #{APP_DOC_NUM}
   AND APP_DOC_CNT = #{APP_DOC_CNT}

UPDATE STOCATCH
   SET DEL_FLAG = '1'
     , MOD_DATE = SYSDATE
     , MOD_USER_ID = 'SYSTEM'
 WHERE GATE_CD = #{GATE_CD}
   AND UUID = #{UUID}
   AND UUID_SQ = #{UUID_SQ}
